<style>
/* Critical CSS - Above the Fold Only */
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}html{scroll-behavior:smooth;font-size:16px}body{font-family:'IBM Plex Sans Arabic',-apple-system,BlinkMacSystemFont,sans-serif;background-color:var(--bg-primary);color:var(--text-primary);line-height:1.6;overflow-x:hidden;-webkit-font-smoothing:antialiased;-moz-osx-font-smoothing:grayscale}.container{max-width:1280px;margin:0 auto;padding:0 24px}.header{position:sticky;top:0;background:linear-gradient(135deg,rgba(15,23,42,0.7) 0%,rgba(30,41,59,0.65) 50%,rgba(15,23,42,0.7) 100%);backdrop-filter:blur(40px)saturate(180%);-webkit-backdrop-filter:blur(40px)saturate(180%);box-shadow:0 8px 32px rgba(0,0,0,0.3),0 0 0 1px rgba(255,255,255,0.05)inset;z-index:1000;border-bottom:2px solid transparent}.navbar{display:flex;align-items:center;justify-content:space-between;padding:16px 0;gap:32px}.logo{display:flex;align-items:center;gap:12px;font-weight:700;font-size:28px;color:var(--text-primary);text-decoration:none;padding:12px 16px;border-radius:16px;background:rgba(255,255,255,0.03);backdrop-filter:blur(10px)}.logo-img{max-height:40px;width:auto}.logo-icon{font-size:36px}.nav-links{display:flex;align-items:center;gap:8px;flex:1;justify-content:center}.nav-link{color:var(--text-secondary);font-weight:500;font-size:16px;padding:12px 20px;border-radius:12px;text-decoration:none;background:rgba(255,255,255,0.02);backdrop-filter:blur(10px)}.nav-actions{display:flex;align-items:center;gap:12px}.btn{display:inline-flex;align-items:center;justify-content:center;gap:16px;padding:16px 32px;height:44px;border-radius:8px;font-weight:600;font-size:16px;cursor:pointer;border:2px solid transparent;white-space:nowrap}.btn-primary{background:linear-gradient(135deg,#10B981 0%,#3B82F6 50%,#8B5CF6 100%);color:#FFF;box-shadow:0 8px 20px rgba(16,185,129,0.4)}.btn-outline{background:rgba(255,255,255,0.03);backdrop-filter:blur(10px);color:var(--text-primary);border:2px solid rgba(16,185,129,0.3)}.hero{min-height:90vh;display:flex;align-items:center;padding:80px 0;background:linear-gradient(135deg,rgba(15,23,42,0.9) 0%,rgba(30,41,59,0.95) 100%)}.hero-content{display:grid;grid-template-columns:1fr 1fr;gap:64px;align-items:center}.hero-title{font-size:clamp(32px,5vw,56px);line-height:1.2;font-weight:700;background:linear-gradient(135deg,#10B981 0%,#3B82F6 50%,#8B5CF6 100%);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text;margin-bottom:24px}.hero-description{font-size:18px;color:var(--text-secondary);margin-bottom:32px;line-height:1.7}.hero-actions{display:flex;gap:16px;margin-bottom:32px}.btn-lg{padding:24px 48px;height:48px;font-size:16px}.hero-stats{display:flex;gap:48px}.stat-item{display:flex;flex-direction:column}.stat-number{font-size:32px;font-weight:700;color:#10B981}.stat-label{font-size:14px;color:var(--text-muted)}.menu-toggle{display:none}
@media (max-width:768px){.nav-links{display:none}.menu-toggle{display:block}.hero-content{grid-template-columns:1fr;gap:32px}.hero-stats{gap:24px}}
</style>
